import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, ActivatedRoute } from '@angular/router';
import { ApiService } from '../../core/api.service';
import { AuthService } from '../../core/services/auth.service';
import { Product } from '../../core/models';

/**
 * Storefront product detail (`products/:id`, public). Shows the product with a
 * quantity picker and add-to-cart control. service_agent wires ApiService.getProduct()
 * and addToCart() in ngOnInit()/addToCart().
 */
@Component({
  selector: 'app-product-detail',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './product-detail.component.html',
  styleUrl: './product-detail.component.css',
})
export class ProductDetailComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);
  readonly added = signal(false);
  readonly qty = signal(1);

  // Mock catalog — service_agent replaces this with ApiService.getProduct(id).
  readonly products = signal<Product[]>([
    {
      id: 'p1',
      name: 'Aurora Wireless Headphones',
      description:
        'Over-ear noise-cancelling headphones with 40-hour battery life, plush memory-foam ear cups, and multipoint Bluetooth. Includes a hard travel case and USB-C fast charging.',
      priceCents: 18900,
      imageUrl: 'https://images.unsplash.com/photo-1505740420928-5e560c06d30e?w=800&q=80',
      stockQty: 24,
    },
    {
      id: 'p4',
      name: 'Lumen Desk Lamp',
      description:
        'Dimmable LED desk lamp with five colour temperatures and a wireless charging base for your phone. Sturdy weighted arm holds any angle.',
      priceCents: 6400,
      imageUrl: 'https://images.unsplash.com/photo-1507473885765-e6ed057f782c?w=800&q=80',
      stockQty: 3,
    },
    {
      id: 'p6',
      name: 'Grove Ceramic Mug Set',
      description:
        'Set of four hand-glazed stoneware mugs in assorted earth tones. Microwave and dishwasher safe. Currently sold out — restock expected soon.',
      priceCents: 4200,
      imageUrl: 'https://images.unsplash.com/photo-1514228742587-6b1558fcca3d?w=800&q=80',
      stockQty: 0,
    },
  ]);

  productId = '';

  readonly product = computed<Product | undefined>(() =>
    this.products().find((p) => p.id === this.productId) ?? this.products()[0],
  );

  constructor(
    private api: ApiService,
    private route: ActivatedRoute,
    public auth: AuthService,
  ) {}

  ngOnInit(): void {
    this.productId = this.route.snapshot.paramMap.get('id') ?? '';
    this.loading.set(true);
    this.error.set(null);
    this.api.getProduct(this.productId).subscribe({
      next: (product) => {
        this.products.set([product]);
        this.loading.set(false);
      },
      error: () => {
        this.error.set('Could not load this product.');
        this.loading.set(false);
      },
    });
  }

  inc(): void {
    const max = this.product()?.stockQty ?? 1;
    this.qty.update((q) => Math.min(max, q + 1));
  }
  dec(): void {
    this.qty.update((q) => Math.max(1, q - 1));
  }

  addToCart(): void {
    const p = this.product();
    if (!p) return;
    this.api.addToCart(p.id, this.qty()).subscribe({
      next: () => {
        this.added.set(true);
      },
      error: () => {
        this.error.set('Could not add to cart.');
      },
    });
  }

  money(cents: number): string {
    return '$' + (cents / 100).toFixed(2);
  }
}
